# Load the provided JSON databases and search for the hadith span.
import json, re, unicodedata, os, sys, textwrap

quran_path = "/mnt/data/file-RhatJL6W5hpishQfBLfQ2a-quranic_verses.json"
hadith_path = "/mnt/data/file-GKgoPWB6fR896BnuZfjrBZ-six_hadith_books.json"

def load_json(path):
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)

quran = load_json(quran_path)
hadith = load_json(hadith_path)

# Normalization helpers
def strip_diacritics(s):
    return "".join(ch for ch in unicodedata.normalize("NFD", s) if unicodedata.category(ch) != "Mn")

def normalize(s):
    s = s.replace("ـ", "")  # tatweel
    s = re.sub(r"[^\w\s]+", " ", s, flags=re.UNICODE)  # remove punctuation
    s = re.sub(r"\s+", " ", s).strip()
    s = s.replace("أ","ا").replace("إ","ا").replace("آ","ا").replace("ى","ي").replace("ؤ","و").replace("ئ","ي")
    return strip_diacritics(s)

query_full = "تعلموا القرآن وغنوا به وأفشوه"
query_norm = normalize(query_full)

# Search in hadith fields hadithTxt or Matn
results = []
for i, rec in enumerate(hadith):
    matn = rec.get("hadithTxt") or rec.get("Matn") or ""
    if not matn:
        continue
    n = normalize(matn)
    if query_norm in n:
        results.append((i, matn, rec.get("source") or rec.get("book") or ""))

len(results)

# If no direct substring, try approximate and token overlap search for similar phrase components.
from difflib import SequenceMatcher

def score(a,b):
    return SequenceMatcher(None, a, b).ratio()

candidates = []
for i, rec in enumerate(hadith):
    matn = rec.get("hadithTxt") or rec.get("Matn") or ""
    if not matn:
        continue
    n = normalize(matn)
    # Look for pieces like "تعلموا القرآن" and "أفشوه" or "غنوا به"
    cond1 = "تعلموا القران" in n
    cond2 = "افشوه" in n
    cond3 = "غنوا به" in n or "غنوا" in n
    if cond1 and (cond2 or cond3):
        candidates.append((i, matn))
    else:
        # compute ratio with query
        r = score(n, query_norm)
        if r > 0.4:
            candidates.append((i, matn))

len(candidates)

