# Search for "غنوا به" or "زينوا القرآن بأصواتكم" to see if alternatives exist in DB
terms = ["غنوا به", "غنوا بالقرآن", "زينوا القرآن بأصواتكم", "حسنوا القرآن بأصواتكم", "تعلموا القرآن"]
def search_terms(terms):
    found = {t: [] for t in terms}
    for i, rec in enumerate(hadith):
        matn = rec.get("hadithTxt") or rec.get("Matn") or ""
        if not matn:
            continue
        for t in terms:
            if normalize(t) in normalize(matn):
                found[t].append((i, matn))
    return found

found = search_terms(terms)
{k: len(v) for k,v in found.items()}, list(found["زينوا القرآن بأصواتكم"])[:1]

